// Write 4-character hex length prefix for pkt-line format
// This centralizes hex encoding logic to avoid duplication
static void write_pktline_hex_header(char* buffer, size_t len) {
    static const char hex_chars[] = "0123456789abcdef";
    buffer[0] = hex_chars[(len >> 12) & 0xF];
    buffer[1] = hex_chars[(len >> 8) & 0xF];
    buffer[2] = hex_chars[(len >> 4) & 0xF];
    buffer[3] = hex_chars[len & 0xF];
}

