TEST(url_parse_https_basic) {
    char host[256], path[256];
    int port;
    bool is_https;

    bool result = test_url_parse("https://github.com/user/repo.git",
                                  host, sizeof(host), path, sizeof(path),
                                  &port, &is_https);

    TEST_ASSERT_TRUE(result);
    TEST_ASSERT_STREQ(host, "github.com");
    TEST_ASSERT_STREQ(path, "/user/repo.git");
    TEST_ASSERT_EQ(port, 443);
    TEST_ASSERT_TRUE(is_https);
}

