TEST(pktline_write_basic) {
    char buffer[256];

    // Write a simple line "hello"
    // Expected: "000ahello\n" (4 hex chars + 5 content + 1 newline = 10 = 0x000a)
    size_t written = test_pktline_write(buffer, sizeof(buffer), "hello");

    TEST_ASSERT_EQ(written, 10);
    TEST_ASSERT_TRUE(memcmp(buffer, "000ahello\n", 10) == 0);
}

TEST(pktline_write_empty_string) {
    char buffer[256];

    // Write an empty line ""
    // Expected: "0005\n" (4 hex chars + 0 content + 1 newline = 5 = 0x0005)
    size_t written = test_pktline_write(buffer, sizeof(buffer), "");

    TEST_ASSERT_EQ(written, 5);
    TEST_ASSERT_TRUE(memcmp(buffer, "0005\n", 5) == 0);
}

TEST(pktline_write_flush) {
    char buffer[16];

    // Flush packet is always "0000"
    size_t written = test_pktline_write_flush(buffer);

    TEST_ASSERT_EQ(written, 4);
    TEST_ASSERT_TRUE(memcmp(buffer, "0000", 4) == 0);
}

TEST(pktline_write_delim) {
    char buffer[16];

    // Delimiter packet is always "0001"
    size_t written = test_pktline_write_delim(buffer);

    TEST_ASSERT_EQ(written, 4);
    TEST_ASSERT_TRUE(memcmp(buffer, "0001", 4) == 0);
}

