TEST(pktline_next_multiple_packets) {
    // Two data packets followed by flush
    // "000ahello\n" + "000bworld!\n" + "0000"
    const char* data = "000ahello\n000bworld!\n0000";
    PktLineParser parser;
    test_pktline_init(&parser, data, strlen(data));

    char line[256];
    int type;

    // First packet: "hello"
    TEST_ASSERT_TRUE(test_pktline_next(&parser, line, sizeof(line), &type));
    TEST_ASSERT_EQ(type, test_get_pktline_data_type());
    TEST_ASSERT_STREQ(line, "hello");

    // Second packet: "world!"
    TEST_ASSERT_TRUE(test_pktline_next(&parser, line, sizeof(line), &type));
    TEST_ASSERT_EQ(type, test_get_pktline_data_type());
    TEST_ASSERT_STREQ(line, "world!");

    // Third packet: flush
    TEST_ASSERT_TRUE(test_pktline_next(&parser, line, sizeof(line), &type));
    TEST_ASSERT_EQ(type, test_get_pktline_flush_type());

    // No more data
    TEST_ASSERT_FALSE(test_pktline_next(&parser, line, sizeof(line), &type));
}

