TEST(pktline_roundtrip) {
    // Write a packet and then read it back
    char write_buffer[256];
    const char* test_content = "test message";

    // Write the packet
    size_t written = test_pktline_write(write_buffer, sizeof(write_buffer), test_content);
    TEST_ASSERT_TRUE(written > 0);

    // Read it back
    PktLineParser parser;
    test_pktline_init(&parser, write_buffer, written);

    char read_buffer[256];
    int type;
    bool result = test_pktline_next(&parser, read_buffer, sizeof(read_buffer), &type);

    TEST_ASSERT_TRUE(result);
    TEST_ASSERT_EQ(type, test_get_pktline_data_type());
    TEST_ASSERT_STREQ(read_buffer, test_content);
}

