// Helper to build a mock v2 discovery response
static size_t build_v2_discovery_response(char* buffer, size_t buffer_size,
                                          const char** capabilities, size_t cap_count) {
    size_t offset = 0;

    // "# service=git-upload-pack\n"
    offset += test_pktline_write(buffer + offset, buffer_size - offset, "# service=git-upload-pack");
    // Flush after service line
    offset += test_pktline_write_flush(buffer + offset);
    // "version 2"
    offset += test_pktline_write(buffer + offset, buffer_size - offset, "version 2");
    // Capabilities
    for (size_t i = 0; i < cap_count; i++) {
        offset += test_pktline_write(buffer + offset, buffer_size - offset, capabilities[i]);
    }
    // End with flush
    offset += test_pktline_write_flush(buffer + offset);

    return offset;
}

// Helper to build a mock v1 discovery response (ref advertisement)
static size_t build_v1_discovery_response(char* buffer, size_t buffer_size,
                                          const char* head_sha, const char* head_ref) {
    size_t offset = 0;

    // "# service=git-upload-pack\n"
    offset += test_pktline_write(buffer + offset, buffer_size - offset, "# service=git-upload-pack");
    // Flush after service line
    offset += test_pktline_write_flush(buffer + offset);

    // First ref line: "<sha> <refname>\0<caps>"
    // Format for v1: "sha ref\0capabilities..."
    char ref_line[512];
    snprintf(ref_line, sizeof(ref_line), "%s %s", head_sha, head_ref);
    offset += test_pktline_write(buffer + offset, buffer_size - offset, ref_line);

    // End with flush
    offset += test_pktline_write_flush(buffer + offset);

    return offset;
}

TEST(discover_v2_success) {
    // Build mock response
    char response[4096];
    const char* caps[] = {"ls-refs", "fetch", "agent=git/2.43.0"};
    size_t response_len = build_v2_discovery_response(response, sizeof(response), caps, 3);

    // Enable mock and queue response
    test_mock_http_reset();
    test_mock_http_enable();
    test_mock_http_queue_response(200, response, response_len);

    // Call discover
    ServerCapabilities server_caps;
    memset(&server_caps, 0, sizeof(server_caps));
    int result = test_proto_v2_discover(L"github.com", 443, true,
                                        L"/user/repo.git",
                                        &server_caps, nullptr, nullptr, 0);

    // Verify
    TEST_ASSERT_EQ(result, test_get_discover_success());
    TEST_ASSERT_TRUE(server_caps.version_2);
    TEST_ASSERT_TRUE(server_caps.ls_refs);
    TEST_ASSERT_TRUE(server_caps.fetch);

    test_mock_http_disable();
    test_mock_http_reset();
}

