// Helper to build mock ls-refs response
// Response format: "<sha> <refname>[ symref-target:<target>][ peeled:<sha>]\n"
static size_t build_ls_refs_response(char* buffer, size_t buffer_size,
                                     const char** sha_list, const char** ref_names,
                                     size_t ref_count) {
    size_t offset = 0;

    for (size_t i = 0; i < ref_count && offset < buffer_size - 50; i++) {
        // Build ref line: "sha refname"
        char ref_line[512];
        snprintf(ref_line, sizeof(ref_line), "%s %s", sha_list[i], ref_names[i]);
        offset += test_pktline_write(buffer + offset, buffer_size - offset, ref_line);
    }

    // End with flush
    offset += test_pktline_write_flush(buffer + offset);

    return offset;
}

// Path to test fixture repository
static const wchar_t* FETCH_TEST_REPO_PATH = L"test\\fixtures\\test_repo";

TEST(fetch_refs_lists_branches) {
    // Open test repo
    GitRepository repo = {};
    if (!git_repo_open(&repo, FETCH_TEST_REPO_PATH)) {
        TEST_SKIP("Fixture repo not found");
    }

    // Build mock discovery response (v2)
    char discovery_response[4096];
    const char* caps[] = {"ls-refs", "fetch"};
    size_t discovery_len = build_v2_discovery_response(discovery_response,
                                                        sizeof(discovery_response), caps, 2);

    // Build mock ls-refs response with branches
    char ls_refs_response[4096];
    const char* shas[] = {
        "abc123def456789012345678901234567890abcd",
        "def456abc789012345678901234567890123abcd",
        "123456789012345678901234567890abcdef1234"
    };
    const char* refs[] = {
        "refs/heads/main",
        "refs/heads/feature",
        "refs/heads/develop"
    };
    size_t ls_refs_len = build_ls_refs_response(ls_refs_response,
                                                 sizeof(ls_refs_response),
                                                 shas, refs, 3);

    // Enable mock and queue responses (discovery first, then ls-refs)
    test_mock_http_reset();
    test_mock_http_enable();
    test_mock_http_queue_response(200, discovery_response, discovery_len);
    test_mock_http_queue_response(200, ls_refs_response, ls_refs_len);

    // Call git_fetch_refs
    GitRemoteRef fetched_refs[10];
    size_t ref_count = 0;
    bool result = git_fetch_refs(&repo, "origin", fetched_refs, &ref_count, 10);

    // Verify
    TEST_ASSERT_TRUE(result);
    TEST_ASSERT_EQ(ref_count, 3);

    // Check refs are properly parsed
    TEST_ASSERT_STREQ(fetched_refs[0].name, "refs/heads/main");
    TEST_ASSERT_STREQ(fetched_refs[0].sha, "abc123def456789012345678901234567890abcd");
    TEST_ASSERT_STREQ(fetched_refs[1].name, "refs/heads/feature");
    TEST_ASSERT_STREQ(fetched_refs[2].name, "refs/heads/develop");

    test_mock_http_disable();
    test_mock_http_reset();
    git_repo_close(&repo);
}

