// Helper to build mock receive-pack discovery response
// Response format: pkt-line "# service=git-receive-pack", flush, then refs with capabilities
static size_t build_receive_pack_discovery_response(char* buffer, size_t buffer_size,
                                                     const char** sha_list, const char** ref_names,
                                                     size_t ref_count, const char* capabilities) {
    size_t offset = 0;

    // "# service=git-receive-pack\n"
    offset += test_pktline_write(buffer + offset, buffer_size - offset, "# service=git-receive-pack");
    // Flush after service line
    offset += test_pktline_write_flush(buffer + offset);

    // First ref includes capabilities (embedded null separator)
    // Format: "<sha> <refname>\0<capabilities>\n"
    for (size_t i = 0; i < ref_count && offset < buffer_size - 200; i++) {
        char ref_line[512];
        if (i == 0 && capabilities) {
            // Build line with embedded null and capabilities
            int ref_part_len = snprintf(ref_line, sizeof(ref_line), "%s %s", sha_list[i], ref_names[i]);
            ref_line[ref_part_len] = '\0';  // Embedded null
            size_t caps_len = strlen(capabilities);
            memcpy(ref_line + ref_part_len + 1, capabilities, caps_len);
            // Total content length (excluding pkt-line header)
            size_t content_len = ref_part_len + 1 + caps_len;
            // Write pkt-line manually for embedded null support
            size_t total_len = 4 + content_len + 1;  // header + content + newline
            char* p = buffer + offset;
            write_pktline_hex_header(p, total_len);
            memcpy(p + 4, ref_line, content_len);
            p[4 + content_len] = '\n';
            offset += total_len;
        } else {
            snprintf(ref_line, sizeof(ref_line), "%s %s", sha_list[i], ref_names[i]);
            offset += test_pktline_write(buffer + offset, buffer_size - offset, ref_line);
        }
    }

    // End with flush
    offset += test_pktline_write_flush(buffer + offset);

    return offset;
}

// Helper to build mock send-pack success response
// Response format: pkt-line "unpack ok", then "ok <refname>" per ref
static size_t build_push_success_response(char* buffer, size_t buffer_size,
                                          const char* ref_name) {
    size_t offset = 0;

    // "unpack ok"
    offset += test_pktline_write(buffer + offset, buffer_size - offset, "unpack ok");

    // "ok refs/heads/main"
    char ok_line[256];
    snprintf(ok_line, sizeof(ok_line), "ok %s", ref_name);
    offset += test_pktline_write(buffer + offset, buffer_size - offset, ok_line);

    // Flush
    offset += test_pktline_write_flush(buffer + offset);

    return offset;
}

// Helper to build mock send-pack rejection response
static size_t build_push_rejection_response(char* buffer, size_t buffer_size,
                                            const char* ref_name, const char* reason) {
    size_t offset = 0;

    // "unpack ok"
    offset += test_pktline_write(buffer + offset, buffer_size - offset, "unpack ok");

    // "ng refs/heads/main non-fast-forward"
    char ng_line[256];
    snprintf(ng_line, sizeof(ng_line), "ng %s %s", ref_name, reason);
    offset += test_pktline_write(buffer + offset, buffer_size - offset, ng_line);

    // Flush
    offset += test_pktline_write_flush(buffer + offset);

    return offset;
}

