    // This is a minimal parser for OAuth responses which don't have extra whitespace
    const char* json = R"({"key":"value with spaces"})";

    char out[64];
    bool result = test_json_extract_string(json, "key", out, sizeof(out));

    TEST_ASSERT_TRUE(result);
