TEST(credential_fill_github_env_token) {
    // Save existing env vars
    char* old_gh_token = getenv("GH_TOKEN");
    char* old_github_token = getenv("GITHUB_TOKEN");

    // Clear both vars to start clean
    _putenv("GH_TOKEN=");
    _putenv("GITHUB_TOKEN=");

    // Set GH_TOKEN
    _putenv("GH_TOKEN=test_token_12345");

    GitCredential cred = {};
    bool result = test_credential_fill("https://github.com/user/repo.git", &cred);

    // Note: May fail if Windows Credential Manager has stored credentials for github.com
    // The credential fill priority is: Credential Manager -> URL embedded -> .gitconfig -> env vars
    // So this test checks if the function succeeds (env var is a valid fallback)
    if (result) {
        // If credentials found, verify they're valid
        TEST_ASSERT_TRUE(cred.username[0] != '\0');
        TEST_ASSERT_TRUE(cred.password[0] != '\0');
    }

    // Restore env vars
    if (old_gh_token) {
        char restore[512];
        snprintf(restore, sizeof(restore), "GH_TOKEN=%s", old_gh_token);
        _putenv(restore);
    } else {
        _putenv("GH_TOKEN=");
    }
    if (old_github_token) {
        char restore[512];
        snprintf(restore, sizeof(restore), "GITHUB_TOKEN=%s", old_github_token);
        _putenv(restore);
    } else {
        _putenv("GITHUB_TOKEN=");
    }
}

