TEST(discover_wrong_service_header) {
    // Server returns wrong service name
    // Note: The implementation is lenient and doesn't validate service header
    // This test verifies the parser doesn't crash on unexpected service names
    char response[4096];
    size_t offset = 0;

    // Wrong service header (should be git-upload-pack)
    offset += test_pktline_write(response + offset, sizeof(response) - offset, "# service=git-wrong-service");
    offset += test_pktline_write_flush(response + offset);
    offset += test_pktline_write(response + offset, sizeof(response) - offset, "version 2");
    offset += test_pktline_write(response + offset, sizeof(response) - offset, "ls-refs");
    offset += test_pktline_write_flush(response + offset);

    test_mock_http_reset();
    test_mock_http_enable();
    test_mock_http_queue_response(200, response, offset);

    ServerCapabilities server_caps;
    memset(&server_caps, 0, sizeof(server_caps));
    int result = test_proto_v2_discover(L"github.com", 443, true,
                                        L"/user/repo.git",
                                        &server_caps, nullptr, nullptr, 0);

    // Implementation is lenient - accepts wrong service header and parses capabilities
    // The important thing is it doesn't crash
    TEST_ASSERT_EQ(result, test_get_discover_success());
    TEST_ASSERT_TRUE(server_caps.version_2);

    test_mock_http_disable();
    test_mock_http_reset();
}

TEST(discover_truncated_capability_line) {
    // Response truncates in the middle of a capability line
    // Note: The implementation is lenient - once "version 2" is parsed,
    // the capability parsing loop exits gracefully on error and returns Success
    char response[4096];
    size_t offset = 0;

    offset += test_pktline_write(response + offset, sizeof(response) - offset, "# service=git-upload-pack");
    offset += test_pktline_write_flush(response + offset);
    offset += test_pktline_write(response + offset, sizeof(response) - offset, "version 2");
    // Now write a packet that claims more length than we provide
    // Header "0020" = 32 bytes total, but we only give partial content
    memcpy(response + offset, "0020ls-refs", 11);  // Only 11 bytes instead of 28 content
    offset += 11;

    test_mock_http_reset();
    test_mock_http_enable();
    test_mock_http_queue_response(200, response, offset);

    ServerCapabilities server_caps;
    memset(&server_caps, 0, sizeof(server_caps));
    int result = test_proto_v2_discover(L"github.com", 443, true,
                                        L"/user/repo.git",
                                        &server_caps, nullptr, nullptr, 0);

    // Implementation is lenient - version 2 was detected, so it returns success
    // even though the capability line was truncated
    // The important thing is it doesn't crash
    TEST_ASSERT_EQ(result, test_get_discover_success());
    TEST_ASSERT_TRUE(server_caps.version_2);
    // Note: ls-refs won't be set because the packet parsing failed

    test_mock_http_disable();
    test_mock_http_reset();
}

