// ============================================================================
// PER-THREAD PACK ACCESS TESTS
// ============================================================================
// These tests verify the thread-safe per-thread pack file access used during
// delta resolution. The original bug was a race condition where multiple threads
// shared a single memory mapping, causing crashes when one thread remapped while
// another was reading.

static const wchar_t* PACK_FIXTURE_PATH = L"test\\fixtures\\packs\\minimal.pack";

TEST(per_thread_pack_access_init_cleanup) {
    // Test basic init/cleanup cycle
    TestPackAccess access;

    // Init with valid pack file
    bool init_ok = test_pack_access_init(&access, PACK_FIXTURE_PATH);
    if (!init_ok) {
        TEST_SKIP("Fixture pack not found");
    }

    TEST_ASSERT_NE(access.pack_file_handle, INVALID_HANDLE_VALUE);
    TEST_ASSERT_TRUE(access.pack_file_size > 0);

    // Cleanup should not crash
    test_pack_access_cleanup(&access);

    // After cleanup, handles should be invalid
    TEST_ASSERT_EQ(access.pack_file_handle, INVALID_HANDLE_VALUE);
    TEST_ASSERT_NULL(access.pack_mapped_view);
    TEST_ASSERT_NULL(access.pack_mapping_handle);
}

TEST(per_thread_pack_access_null_params) {
    // Test null parameter handling
    TEST_ASSERT_FALSE(test_pack_access_init(nullptr, PACK_FIXTURE_PATH));
    TEST_ASSERT_FALSE(test_pack_access_init(nullptr, nullptr));

    TestPackAccess access;
    TEST_ASSERT_FALSE(test_pack_access_init(&access, nullptr));

    // Cleanup with null should not crash
    test_pack_access_cleanup(nullptr);
}

TEST(per_thread_pack_access_get_view_basic) {
    TestPackAccess access;
    if (!test_pack_access_init(&access, PACK_FIXTURE_PATH)) {
        TEST_SKIP("Fixture pack not found");
    }

    // Get view at offset 0
    size_t available = 0;
    const void* view = test_pack_access_get_view(&access, 0, &available);

    TEST_ASSERT_NOT_NULL(view);
    TEST_ASSERT_TRUE(available > 0);

    // Verify pack signature "PACK"
    TEST_ASSERT_EQ(memcmp(view, "PACK", 4), 0);

    test_pack_access_cleanup(&access);
}

TEST(per_thread_pack_access_get_view_multiple_offsets) {
    TestPackAccess access;
    if (!test_pack_access_init(&access, PACK_FIXTURE_PATH)) {
        TEST_SKIP("Fixture pack not found");
    }

    // Access multiple offsets to trigger potential remapping
    size_t offsets[] = {0, 100, 1000, 500, 0, 2000};
    int num_offsets = sizeof(offsets) / sizeof(offsets[0]);

    for (int i = 0; i < num_offsets; i++) {
        if (offsets[i] >= access.pack_file_size) continue;

        size_t available = 0;
        const void* view = test_pack_access_get_view(&access, offsets[i], &available);

        TEST_ASSERT_NOT_NULL(view);
        TEST_ASSERT_TRUE(available > 0);
    }

    test_pack_access_cleanup(&access);
}

TEST(per_thread_pack_access_concurrent_8_threads) {
    // This is the key test that exercises the thread-safety fix.
    // Before the fix, this would crash due to race conditions when
    // multiple threads shared a single memory mapping.

    // Skip if fixture not available
    HANDLE test_file = CreateFileW(PACK_FIXTURE_PATH, GENERIC_READ, FILE_SHARE_READ,
                                    nullptr, OPEN_EXISTING, FILE_ATTRIBUTE_NORMAL, nullptr);
    if (test_file == INVALID_HANDLE_VALUE) {
        TEST_SKIP("Fixture pack not found");
    }
    CloseHandle(test_file);

    // Run concurrent access test with 8 threads (typical delta resolution config)
    // Each thread does 100 accesses at different offsets
    bool success = test_concurrent_pack_access(PACK_FIXTURE_PATH, 8, 100);

    TEST_ASSERT_TRUE(success);
}

